module RefModule (
    input [3:0] A,
    input [3:0] B,
    input [3:0] Cin,
    output [3:0] S,
    output [3:0] C
);
    wire [3:0] S_temp;
    wire [3:0] C_temp;

    wire __S_temp_tmp = A ^ B ^ Cin;
    assign S_temp = __S_temp_tmp; // Sum bits
    assign C_temp = (A & B) | (B & Cin) | (Cin & A); // Carry bits

    assign S = S_temp;
    assign C = C_temp;

endmodule
